//codeMirror

function loadCodeMirror(callback) {
    if (window.CodeMirror) return callback();

    const css = document.createElement("link");
    css.rel = "stylesheet";
    css.href = "https://cdnjs.cloudflare.com/ajax/libs/codemirror/5.65.16/codemirror.min.css";

    const script = document.createElement("script");
    script.src = "https://cdnjs.cloudflare.com/ajax/libs/codemirror/5.65.16/codemirror.min.js";

    const mode = document.createElement("script");
    mode.src = "https://cdnjs.cloudflare.com/ajax/libs/codemirror/5.65.16/mode/javascript/javascript.min.js";
    const addon = document.createElement("script");
    addon.src = "https://cdnjs.cloudflare.com/ajax/libs/codemirror/5.65.16/addon/edit/closebrackets.min.js";

    document.head.appendChild(css);
    document.head.appendChild(script);
    script.onload = () => {
        document.head.appendChild(mode);
        mode.onload = () => {
            document.head.appendChild(addon);
            addon.onload = callback;
        };
    };
    const style = document.createElement("style");
    style.textContent = `
    .CodeMirror {
        background: #858585;
        color: #000000;
        font-family: Consolas, monospace;
        font-size: 14px;
        border: 2px solid #000000;
        border-radius: 10px;
    }

    .newInlineJSFuncCreationInputField:focus {
        border: 5px solid #004d69;
        box-shadow: none;
        outline: none;
    }
    `;
    document.head.appendChild(style);
}
(function() {
    const vm = Scratch.vm;
    const runtime = vm.runtime;
    const extIcon = "data:image/svg+xml;base64,"
    const funcIcon = "data:image/svg+xml;base64,"
    let parentExtension = null;
    class JSeval {
        constructor() {
            parentExtension = this;
            this.functions = {};
            this.activations=null;
            this.hideLegacy=true;

            vm.runtime.on("PROJECT_LOADED", () => {
                this._setupExtensionStorage();
                this.loadFunctions();
            });
        }

        getInfo() {
            return {
                id: 'jseval',
                name: 'evaluate+',
                color1: "#393939",
                menuIconURI: extIcon,
                blocks: [
                    {
                        blockType: Scratch.BlockType.BUTTON,
                        func: "viewJS",
                        text: "JS functions",
                    },
                    "---",
                    {
                        opcode: 'getFunc',
                        blockType: Scratch.BlockType.REPORTER,
                        text: 'value of JS function [N]',
                        arguments: {
                            N: {
                                type: Scratch.ArgumentType.STRING,
                                menu: "FUNCLIST"
                            }
                        }
                    },
                    {
                        opcode: 'runFunc',
                        blockType: Scratch.BlockType.COMMAND,
                        text: 'run JS function [N]',
                        arguments: {
                            N: {
                                type: Scratch.ArgumentType.STRING,
                                menu: "FUNCLIST"
                            }
                        }
                    },
                    "---",
                    {
                        blockType: Scratch.BlockType.EVENT,
                        opcode: 'targetedFuncActivation',
                        text: 'When activated by JS function [FN]',
                        isEdgeActivated: false,
                        arguments: {
                            FN: {
                                type: Scratch.ArgumentType.STRING,
                                menu: "ARGLESSFUNCLIST"
                            }
                        }
                    },
                    {
                        blockType: Scratch.BlockType.EVENT,
                        opcode: 'funcActivation',
                        text: 'When activated by any JS function',
                        isEdgeActivated: false,
                    },
                    {
                        blockType: Scratch.BlockType.BUTTON,
                        func: "refreshBlocks",
                        text: "refresh block palette"
                    },
                    {
                        blockType: Scratch.BlockType.BUTTON,
                        func: "showLegacy",
                        text: "show legacy blocks",
                        hideFromPalette: !this.hideLegacy
                    },

                    {
                        opcode: 'sectionLegacy',
                        blockType: Scratch.BlockType.LABEL,
                        text: 'legacy blocks',
                        hideFromPalette: this.hideLegacy
                    },
                    {
                        opcode: 'JSevalBlock',
                        blockType: Scratch.BlockType.COMMAND,
                        text: 'evauluate [C]',
                        arguments: {
                            C: {
                                type: Scratch.ArgumentType.STRING
                            }
                        },
                        hideFromPalette: this.hideLegacy
                    },
                    {
                        opcode: 'newFunc',
                        blockType: Scratch.BlockType.COMMAND,
                        text: 'create new JS function [N]',
                        arguments: {
                            N: {
                                type: Scratch.ArgumentType.STRING,
                                defaultValue: "a"
                            }
                        },
                        hideFromPalette: this.hideLegacy
                    },
                    {
                        opcode: 'delFunc',
                        blockType: Scratch.BlockType.COMMAND,
                        text: 'delete JS function [N]',
                        arguments: {
                            N: {
                                type: Scratch.ArgumentType.STRING,
                                defaultValue: "a"
                            }
                        },
                        hideFromPalette: this.hideLegacy
                    },
                    {
                        opcode: 'funcAddLine',
                        blockType: Scratch.BlockType.COMMAND,
                        text: 'add line [V] to JS function [N]',
                        arguments: {
                            V: {
                                type: Scratch.ArgumentType.STRING,
                                defaultValue: "alert('hi')"
                            },
                            N: {
                                type: Scratch.ArgumentType.STRING,
                                defaultValue: "a"
                            }
                        },
                        hideFromPalette: this.hideLegacy
                    },
                ],
                menus: {
                    FUNCLIST: {
                        acceptReporters: true,
                        items: "functionsMenu"
                    },
                    ARGLESSFUNCLIST: {
                        acceptReporters: false,
                        items: "functionsMenu"
                    }
                }
            };
        }
        showLegacy(){
            if (confirm('These legacy blocks are extremely outdated and were used for debugging in eariler versions. They are extremely manual and have no use now. Show legacy blocks anyway?')){
                this.hideLegacy=false;
                Scratch.vm.extensionManager.refreshBlocks();
            }
        }
        refreshBlocks(){
            if (true){
                const phl = this.hideLegacy;
                this.hideLegacy=false
                Scratch.vm.extensionManager.refreshBlocks();//temporaily show legacy blocks
                if (phl);{
                this.hideLegacy=true//if legacy blocks were originally hidden, re hide em :3
                Scratch.vm.extensionManager.refreshBlocks();//force a block palette refresh
                }
            }
        }
        functionsMenu() {
        return Object.keys(this.functions).length == 0
            ? ["no functions defined yet"]
            : Object.keys(this.functions);
        }
        //Stolen from ObviousAlex :3
        _setupExtensionStorage() {
            if (!runtime.extensionStorage) return;

            if (!runtime.extensionStorage["jseval"]) {
                console.log("creating empty functions dict");
                runtime.extensionStorage["jseval"] = {
                    functions: {}
                };
            }
        }
        loadFunctions() {
            if (!runtime.extensionStorage?.["jseval"]) return;
            console.log(runtime.extensionStorage["jseval"].functions);

            this.functions = runtime.extensionStorage["jseval"].functions || {};
        }

        saveFunctions() {
            if (!runtime.extensionStorage?.["jseval"]) {
                console.log("missing extension storage for some reason...hmmm");
                console.log("attempting to fix...");
                this._setupExtensionStorage();
            };
            console.log("saving...");
            runtime.extensionStorage["jseval"].functions = this.functions;
            console.log("exension storage saved!");
            Scratch.vm.extensionManager.refreshBlocks();
        }
        JSevalBlock(args){
            eval(args.C)
        }
        newFunc(args){
            this.functions[args.N] = this.functions[args.N] || ""
            this.saveFunctions();
        }
        delFunc(args){
            delete this.functions[args.N];
            this.saveFunctions();
        }
        listFuncs(){
            this.saveFunctions();
            return Object.keys(this.functions).length>=1?Object.keys(this.functions):["no functions defined"]
        }
        funcAddLine(args){
            if (this.functions[args.N] !== undefined){
                this.functions[args.N] = `${this.functions[args.N]}${args.V};\n`;
            } else {
                console.warn("Function not defined:", args.N);
            }
            this.saveFunctions();
        }
        getFunc(args){
            return this.functions[args.N] || `no function named ${args.N} defined.`;
        }
        runFunc(args){
            this.saveFunctions();
            //defining custom functions that you can run from within your JS functions (they can technically be acheived in vanilla JS, these just add convenience :3)
            const triggerHats =  function() {//u can call this function inside ur custom JS scripts to make activate all hat blocks
                runtime.startHats('jseval_funcActivation');
                runtime.startHats('jseval_targetedFuncActivation', {FN: args.N});
            }
            const setVar = function(tVar,nVal){//self explainatory
                const targetedV = runtime.getTargetForStage().lookupVariableByNameAndType(tVar, "");
                if (!targetedV) {return;}//stop early if no variable of this sort exists
                targetedV.value = nVal;
            }
            const getVar = function(tVar){//ALSO self explainatory!
                const targetedV = runtime.getTargetForStage().lookupVariableByNameAndType(tVar, "");
                return targetedV ? targetedV : "";
                
            }
            eval(this.functions[args.N]);  
        }
        //UI nonsense.
        initOverlay(){
            const overlay = document.createElement('div');
            overlay.style.position = 'fixed';
            overlay.style.top = '50%';
            overlay.style.left = '50%';
            overlay.style.transform = 'translate(-50%, -50%)';
            overlay.style.width = '100vw';
            overlay.style.height = '100vh';
            overlay.style.backgroundColor = '#d4d4d4';
            overlay.style.zIndex = '10000';
            overlay.style.display = 'flex';
            overlay.style.flexDirection = 'column';
            overlay.style.alignItems="center"
            overlay.style.border = '0';
            overlay.style.overflowY = 'auto';
            return overlay;
        }
        initButtonRow(headerText) {
            const buttonRow = document.createElement('div');
            buttonRow.style.display = 'flex';
            buttonRow.style.justifyContent = 'flex-start';
            buttonRow.style.alignItems='center';
            buttonRow.style.width = '90%';
            buttonRow.style.gap="10px";
            buttonRow.style.marginBottom = '10px';
            buttonRow.style.marginTop = '10px';
            const pgHeader = document.createElement('p');
            pgHeader.style.fontSize="30px";
            pgHeader.textContent=headerText;
            pgHeader.style.color="#000000"
            buttonRow.appendChild(pgHeader);
            return buttonRow;
        }
        async editContent(funcName){
            //document.body.removeChild(document.getElementById("listOfJSFilesAddedByJSEvalExtension"));
            const overlay=this.initOverlay()
            const buttonRow=this.initButtonRow(`Editing JS function \'${funcName}\'`)
            const closeButton = document.createElement('button');
            closeButton.innerText = 'Close';
            closeButton.style.padding = '5px 10px';
            closeButton.style.cursor = 'pointer';
            closeButton.style.border = '5px solid #600101';
            closeButton.style.borderRadius = '9999px';
            closeButton.style.backgroundColor = '#f44336';
            closeButton.style.color = 'white';
            closeButton.style.fontSize="30px";
            closeButton.addEventListener('click', () => {
                if (overlay._editor.getValue()!=this.functions[funcName]) {
                    if(confirm("you have unsaved changes. Exit anyway?")){
                        document.body.removeChild(overlay)
                    }
                }
                else{document.body.removeChild(overlay);}
                
            });
            const saveButton = document.createElement('button');
            saveButton.innerText = 'Save file';
            saveButton.style.padding = '5px 10px';
            saveButton.style.cursor = 'pointer';
            saveButton.style.border = '5px solid #004215';
            saveButton.style.borderRadius = '9999px';
            saveButton.style.backgroundColor = '#009a27';
            saveButton.style.color = 'white';
            saveButton.style.fontSize="30px";
            saveButton.addEventListener('click', () => {
                this.functions[funcName] = overlay._editor.getValue();
                this.saveFunctions();
            });
            buttonRow.appendChild(closeButton);
            buttonRow.appendChild(saveButton);
            overlay.appendChild(buttonRow);
            const editorContainer = document.createElement('div');
            editorContainer.style.width = "95%";
            editorContainer.style.height = "75%";
            editorContainer.style.border = "0px";
            editorContainer.style.borderRadius = "5px";
            editorContainer.style.overflow = "hidden";
            editorContainer.style.display='flex';
            editorContainer.style.justifyContent='center';
            overlay.appendChild(editorContainer);
            loadCodeMirror(() => {
                const editor = CodeMirror(editorContainer, {
                    value: this.functions[funcName] || "",
                    mode: "javascript",
                    lineNumbers: true,
                    autoCloseBrackets: true,
                    autoCloseQuotes: true
                });
                editor.setSize("90%", "90%");
                setTimeout(() => {
                    editor.refresh();
                }, 50);
                overlay._editor = editor;
            });
            document.body.appendChild(overlay);
        }
        async viewJS() {
            this.saveFunctions()
            const overlay=this.initOverlay()
            const buttonRow=this.initButtonRow("JS functions stored in project: ")
            const closeButton = document.createElement('button');
            closeButton.innerText = 'Close';
            closeButton.style.padding = '5px 10px';
            closeButton.style.cursor = 'pointer';
            closeButton.style.border = '5px solid #600101';
            closeButton.style.borderRadius = '9999px';
            closeButton.style.backgroundColor = '#f44336';
            closeButton.style.color = 'white';
            closeButton.style.fontSize="30px";
            closeButton.addEventListener('click', () => {
                document.body.removeChild(overlay);
                this.refreshBlocks();
                //this.showLegacy();
            });
            const newFuncButton = document.createElement('button');
            newFuncButton.innerText = 'New function';
            newFuncButton.style.padding = '5px 10px';
            newFuncButton.style.cursor = 'pointer';
            newFuncButton.style.border = '5px solid #004d69';
            newFuncButton.style.borderRadius = '9999px';
            newFuncButton.style.backgroundColor = '#14c6e5';
            newFuncButton.style.color = 'white';
            newFuncButton.style.fontSize="30px";
            newFuncButton.addEventListener('click', () => {
            const antiButtonOverlay = document.createElement('div');
                antiButtonOverlay.style.position = 'fixed';
                antiButtonOverlay.style.top = '50%';
                antiButtonOverlay.style.left = '50%';
                antiButtonOverlay.style.transform = 'translate(-50%, -50%)';
                antiButtonOverlay.style.width = '100vw';
                antiButtonOverlay.style.height = '100vh';
                antiButtonOverlay.style.backgroundColor = '#161616ba';
                antiButtonOverlay.style.zIndex = '10001';
                antiButtonOverlay.style.display = 'flex';
                antiButtonOverlay.style.flexDirection = 'column';
                antiButtonOverlay.style.alignItems="center"
                antiButtonOverlay.style.border = '0';
                antiButtonOverlay.style.overflowY = 'auto';
                overlay.appendChild(antiButtonOverlay);
                const inputOverlay = document.createElement('div');
                inputOverlay.style.position = 'fixed';
                inputOverlay.style.top = '50%';
                inputOverlay.style.left = '50%';
                inputOverlay.style.transform = 'translate(-50%, -50%)';
                inputOverlay.style.background = 'white';
                inputOverlay.style.padding = '20px';
                inputOverlay.style.border = '5px solid black';
                inputOverlay.style.zIndex = '10002';
                inputOverlay.style.display = 'flex';
                inputOverlay.style.flexDirection = 'column';
                inputOverlay.style.gap = '10px';
                inputOverlay.style.borderRadius = "15px";
                const input = document.createElement('input');
                input.placeholder = "Function name";
                input.style.padding = '5px';
                input.style.color="#000000"
                input.style.border = '5px solid #004d69';
                input.style.borderRadius = '9999px';
                input.style.backgroundColor = '#14c6e5';
                input.style.height='25px'
                input.classList.add('newInlineJSFuncCreationInputField')
                const confirm = document.createElement('button');
                confirm.innerText = "Create";
                confirm.style.border = '5px solid #004d69';
                confirm.style.borderRadius = '9999px';
                confirm.style.backgroundColor = '#14c6e5';
                confirm.style.height = '50px';
                confirm.color = '#000'
                confirm.fontSize= '20px'
                const cancel = document.createElement('button');
                cancel.innerText = "Cancel";
                cancel.style.border = '5px solid #004d69';
                cancel.style.borderRadius = '9999px';
                cancel.style.backgroundColor = '#14c6e5';
                cancel.style.height = '50px';
                cancel.color = '#000'
                confirm.fontSize= '20px'
                confirm.onclick = () => {
                    const name = input.value.trim();
                    if (!name) return;
                    if (this.functions[name] !== undefined) {
                        alert("Function already exists!");
                        return;
                    }
                    this.functions[name] = "";
                    Scratch.vm.extensionManager.refreshBlocks();
                    this.saveFunctions();
                    overlay.removeChild(antiButtonOverlay);
                    document.body.removeChild(inputOverlay);
                    if (overlay && overlay.parentNode) {
                        overlay.parentNode.removeChild(overlay);
                    }
                    this.viewJS();
                };
                cancel.onclick = () => {
                    overlay.removeChild(antiButtonOverlay);
                    document.body.removeChild(inputOverlay);
                };
                inputOverlay.appendChild(input);
                inputOverlay.appendChild(confirm);
                inputOverlay.appendChild(cancel);
                document.body.appendChild(inputOverlay);
                input.focus();
            });
            buttonRow.appendChild(closeButton);
            buttonRow.appendChild(newFuncButton);
            overlay.appendChild(buttonRow);
            // Loop through dictionary keys
            for (const funcName in this.functions) {
                if (this.functions.hasOwnProperty(funcName)) {
                    const selectButton = document.createElement('button');
                    selectButton.style.display = "flex";
                    selectButton.style.alignItems = "center";
                    selectButton.style.gap = "8px";
                    const icon = document.createElement('img');
                    icon.src = funcIcon;
                    icon.style.width = "39px";
                    icon.style.height = "39px";
                    icon.style.flexShrink = "0";
                    const label = document.createElement('span');
                    label.textContent = funcName;
                    selectButton.appendChild(icon);
                    selectButton.appendChild(label);
                    selectButton.style.padding = '10px';
                    selectButton.style.margin = '5px 0';
                    selectButton.style.cursor = 'pointer';
                    selectButton.style.width = "90%";
                    selectButton.style.height="50px";
                    selectButton.style.border = '2px solid #8e8e8e';
                    selectButton.style.borderRadius = '5px';
                    selectButton.style.fontSize = '20px';
                    selectButton.style.backgroundColor = '#696969';
                    selectButton.style.color="#c0c0c0"
                    selectButton.style.display="flex"
                    selectButton.style.justifyContent="flex-start"
                    // Call the function when button clicked
                    selectButton.addEventListener('click', () => {
                        this.editContent(funcName)
                    });
                    overlay.appendChild(selectButton);
                }
            }
            document.body.appendChild(overlay);
        }
    }
    Scratch.extensions.register(new JSeval());
})();
